files.content:
@tailwind base;
@tailwind components;
@tailwind utilities;

:root {
  --bg: #f6f7fb;
  --bg-elevated: rgba(255, 255, 255, 0.72);
  --bg-strong: #ffffff;
  --text: #121722;
  --text-muted: #5e687c;
  --border: rgba(20, 31, 56, 0.12);
  --brand: #e24d33;
  --brand-2: #2f6df6;
  --success: #1f9d63;
  --warning: #d18a18;

  --radius-sm: 10px;
  --radius-md: 14px;
  --radius-lg: 20px;

  --shadow-sm: 0 2px 10px rgba(14, 24, 45, 0.06);
  --shadow-md: 0 14px 34px rgba(14, 24, 45, 0.1);
  --shadow-lg: 0 28px 60px rgba(14, 24, 45, 0.18);

  --space-1: 0.25rem;
  --space-2: 0.5rem;
  --space-3: 0.75rem;
  --space-4: 1rem;
  --space-5: 1.25rem;
  --space-6: 1.5rem;
  --space-8: 2rem;
  --space-10: 2.5rem;

  --max-width: 1120px;
}

@media (prefers-color-scheme: dark) {
  :root {
    --bg: #090d18;
    --bg-elevated: rgba(16, 24, 42, 0.72);
    --bg-strong: #111a2d;
    --text: #eef2ff;
    --text-muted: #9eabc8;
    --border: rgba(151, 168, 204, 0.24);
    --brand: #ff7055;
    --brand-2: #6f98ff;
    --shadow-sm: 0 2px 10px rgba(0, 0, 0, 0.24);
    --shadow-md: 0 14px 34px rgba(0, 0, 0, 0.34);
    --shadow-lg: 0 28px 60px rgba(0, 0, 0, 0.45);
  }
}

*,
*::before,
*::after {
  box-sizing: border-box;
}

html,
body {
  width: 100%;
  min-height: 100%;
}

body {
  margin: 0;
  color: var(--text);
  background:
    radial-gradient(50rem 30rem at 10% -10%, color-mix(in srgb, var(--brand-2) 16%, transparent), transparent 70%),
    radial-gradient(42rem 24rem at 95% -15%, color-mix(in srgb, var(--brand) 18%, transparent), transparent 72%),
    var(--bg);
  font-family: Inter, ui-sans-serif, system-ui, -apple-system, Segoe UI, Roboto, Helvetica, Arial, sans-serif;
  text-rendering: optimizeLegibility;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

::selection {
  background: color-mix(in srgb, var(--brand-2) 30%, transparent);
  color: var(--text);
}

a {
  color: inherit;
  text-decoration: none;
}

img,
svg,
video,
canvas {
  display: block;
  max-width: 100%;
}

button,
input,
select,
textarea {
  color: inherit;
  font: inherit;
}

:focus-visible {
  outline: 2px solid color-mix(in srgb, var(--brand-2) 70%, white 8%);
  outline-offset: 2px;
}

.app-body {
  min-height: 100dvh;
}

.skip-link {
  position: fixed;
  left: 50%;
  top: var(--space-4);
  z-index: 100;
  transform: translate(-50%, -160%);
  transition: transform 180ms ease;
  background: var(--bg-strong);
  border: 1px solid var(--border);
  border-radius: 999px;
  padding: var(--space-2) var(--space-4);
  box-shadow: var(--shadow-sm);
}

.skip-link:focus-visible {
  transform: translate(-50%, 0%);
}

.app-shell {
  position: relative;
  isolation: isolate;
  min-height: 100dvh;
  display: grid;
  grid-template-rows: auto 1fr auto;
  overflow: clip;
}

.ambient {
  position: absolute;
  z-index: -1;
  filter: blur(34px);
  opacity: 0.55;
  pointer-events: none;
  animation: float 14s ease-in-out infinite;
}

.ambient-top {
  width: 24rem;
  height: 24rem;
  top: -10rem;
  right: -6rem;
  background: color-mix(in srgb, var(--brand-2) 70%, transparent);
}

.ambient-bottom {
  width: 22rem;
  height: 22rem;
  bottom: -8rem;
  left: -5rem;
  background: color-mix(in srgb, var(--brand) 74%, transparent);
  animation-delay: -4.5s;
}

.shell-header {
  position: sticky;
  top: 0;
  z-index: 20;
  border-bottom: 1px solid var(--border);
  background: color-mix(in srgb, var(--bg-elevated) 88%, transparent);
  backdrop-filter: saturate(130%) blur(14px);
}

.shell-inner {
  width: min(var(--max-width), calc(100% - 2rem));
  margin-inline: auto;
}

.shell-header .shell-inner {
  min-height: 4rem;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--space-4);
}

.shell-brand {
  display: inline-flex;
  align-items: center;
  gap: 0.65rem;
  font-weight: 800;
  letter-spacing: 0.01em;
}

.brand-mark {
  width: 0.95rem;
  aspect-ratio: 1;
  border-radius: 999px;
  background: linear-gradient(130deg, var(--brand), var(--brand-2));
  box-shadow: 0 0 0 3px color-mix(in srgb, var(--brand) 24%, transparent);
}

.brand-text {
  font-size: clamp(1rem, 0.65vw + 0.9rem, 1.25rem);
}

.status-chip {
  margin: 0;
  display: inline-flex;
  align-items: center;
  border: 1px solid var(--border);
  border-radius: 999px;
  padding: 0.35rem 0.75rem;
  font-size: 0.82rem;
  line-height: 1;
  color: var(--text-muted);
  background: color-mix(in srgb, var(--bg-strong) 72%, transparent);
}

.shell-main {
  padding-block: clamp(var(--space-6), 3vw, var(--space-10));
}

.shell-content {
  display: grid;
  gap: var(--space-6);
}

.shell-footer {
  border-top: 1px solid var(--border);
  margin-top: var(--space-8);
  background: color-mix(in srgb, var(--bg-elevated) 92%, transparent);
}

.footer-grid {
  padding-block: var(--space-4);
  display: grid;
  gap: var(--space-1);
}

.footer-grid p {
  margin: 0;
  color: var(--text-muted);
  font-size: 0.9rem;
}

.surface-card {
  border: 1px solid var(--border);
  border-radius: var(--radius-lg);
  background: color-mix(in srgb, var(--bg-strong) 82%, transparent);
  box-shadow: var(--shadow-sm);
}

.interactive-card {
  transition:
    transform 180ms ease,
    border-color 180ms ease,
    box-shadow 180ms ease;
}

.interactive-card:hover {
  transform: translateY(-2px);
  border-color: color-mix(in srgb, var(--brand-2) 35%, var(--border));
  box-shadow: var(--shadow-md);
}

@keyframes float {
  0%,
  100% {
    transform: translateY(0) scale(1);
  }
  50% {
    transform: translateY(-12px) scale(1.03);
  }
}

@media (max-width: 768px) {
  .shell-inner {
    width: min(var(--max-width), calc(100% - 1.25rem));
  }

  .shell-header .shell-inner {
    min-height: 3.6rem;
  }

  .status-chip {
    font-size: 0.75rem;
    padding: 0.3rem 0.6rem;
  }

  .footer-grid p {
    font-size: 0.82rem;
  }
}

@media (prefers-reduced-motion: reduce) {
  *,
  *::before,
  *::after {
    animation-duration: 0.01ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.01ms !important;
    scroll-behavior: auto !important;
  }
}
